const EXPLANATION_TEXTS = {
  vattenfall: {
    title: "À propos de Vattenfall",
    description: "Vattenfall est un fournisseur d'énergie suédois établi depuis plusieurs années en France. C'est le premier partenaire historique d'Ideel en énergie. Vattenfall offre un service client fiable et réactif. Si vous consommez de l'électricité et du gaz, c'est le fournisseur à privilégier."
  },
  alpiq_energie: {
    title: "À propos d'Alpiq",
    description: "Alpiq est l'équivalent d'EDF en Suisse. C'est un partenaire d'Ideel depuis 2022, qui propose des tarifs parmi les plus attractifs du marché. Depuis le lancement de notre partenariat, plus de 6000 utilisateurs d'Ideel sont partis chez Alpiq, avec à chaque fois des excellents retours."
  },
  elmy_energie: {
    title: "À propos d'Elmy",
    description: "Elmy est le plus récent des partenaires d'Ideel (2024). C'est un fournisseur d'énergie verte, qui mise avant tout sur la proximité et la transparence. En choisissant Elmy, vous supportez le développement d'une énergie 100% renouvelable produite en France."
  },
  ohm_energie: {
    title: "À propos d'OHM Énergie",
    description: "OHM Énergie est un fournisseur alternatif français d'électricité et de gaz, engagé dans la transition énergétique. Présent sur le marché depuis 2018, il propose des offres souvent parmi les plus compétitives, notamment sur le kWh. Plusieurs milliers d'utilisateurs Ideel ont déjà fait le choix d'OHM."
  }
};
function createCard(partner) {
  const energyCard = document.createElement("div");
  energyCard.className = "energy-card";
  energyCard.id = "card1";
  const headerSection = document.createElement("div");
  headerSection.className = "header-section";
  const logoBox = document.createElement("div");
  logoBox.className = "logo-box";
  logoBox.style.backgroundColor = partner.color;
  const logoImg = document.createElement("img");
  logoImg.src = `https://s3.eu-west-3.amazonaws.com/ideel.images/logos/${partner.label}.png`;
  logoBox.appendChild(logoImg);
  const overlay = document.querySelector(".info-overlay");
  const infoPopup = overlay.querySelector(".info-popup");
  const infoTitle = overlay.querySelector(".info-title");
  const infoText = overlay.querySelector(".info-text");
  const infoIcon = document.createElement("div");
  infoIcon.className = "info-icon";
  infoIcon.textContent = "?";
  infoIcon.addEventListener("click", event => {
    const posY = event.clientY;
    infoTitle.textContent = EXPLANATION_TEXTS[partner.label].title;
    infoText.textContent = EXPLANATION_TEXTS[partner.label].description;
    infoPopup.style.top = `${posY}px`;
    overlay.classList.add("active");
  });
  headerSection.appendChild(logoBox);
  headerSection.appendChild(infoIcon);
  energyCard.appendChild(headerSection);
  const providerName = document.createElement("h2");
  providerName.className = "provider-name";
  providerName.textContent = partner.name;
  energyCard.appendChild(providerName);
  const offerName = document.createElement("p");
  offerName.className = "offer-name";
  offerName.textContent = partner.offerName;
  energyCard.appendChild(offerName);
  const largePriceBox = document.createElement("div");
  largePriceBox.className = "large-price-box";
  if (partner.priceText) {
    const priceBox1 = document.createElement("div");
    priceBox1.className = "price-box mini-box";
    const comparisonText = document.createElement("p");
    comparisonText.className = "comparison";
    comparisonText.textContent = partner.priceText;
    priceBox1.appendChild(comparisonText);
    largePriceBox.appendChild(priceBox1);
  }
  if (partner.diffAmountText) {
    const priceBox2 = document.createElement("div");
    priceBox2.className = "price-box mini-box";
    const economiesText = document.createElement("p");
    economiesText.className = "economies";
    economiesText.textContent = partner.diffAmountText;
    economiesText.style.color = partner.priceColor;
    priceBox2.appendChild(economiesText);
    largePriceBox.appendChild(priceBox2);
  }
  energyCard.appendChild(largePriceBox);
  if (partner.electricityPrice) {
    const electricityPriceDetails = document.createElement("div");
    electricityPriceDetails.className = "price-details";
    const headerRow = document.createElement("div");
    headerRow.style.display = "flex";
    headerRow.style.justifyContent = "space-between";
    headerRow.style.alignItems = "center";
    headerRow.style.marginBottom = "15px";
    const title = document.createElement("h3");
    title.className = "price-category";
    title.textContent = "Électricité";
    title.style.margin = "0";
    headerRow.appendChild(title);
    if (partner.diffPercentageText) {
      const percentageEconomised = document.createElement("div");
      percentageEconomised.className = "detail-line";
      const percentageEconomisedlabel = document.createElement("span");
      const percentageEconomisedValueDiv = document.createElement("div");
      percentageEconomisedValueDiv.className = "percentage-economised-value-div";
      percentageEconomisedValueDiv.style.backgroundColor = partner.priceColor;
      const percentageEconomisedValue = document.createElement("span");
      percentageEconomisedValue.textContent = partner.diffPercentageText;
      percentageEconomisedValue.style.color = "white";
      percentageEconomised.appendChild(percentageEconomisedlabel);
      percentageEconomisedValueDiv.appendChild(percentageEconomisedValue);
      percentageEconomised.appendChild(percentageEconomisedValueDiv);
      headerRow.appendChild(percentageEconomised);
    }
    electricityPriceDetails.appendChild(headerRow);
    const price = document.createElement("div");
    price.className = "detail-line";
    const label = document.createElement("span");
    label.textContent = "Prix de l'abonnement";
    const value = document.createElement("span");
    value.textContent = partner.electricityPrice;
    price.appendChild(label);
    price.appendChild(value);
    electricityPriceDetails.appendChild(price);
    if (partner.electricityKwhPrice) {
      const priceKwh = document.createElement("div");
      priceKwh.className = "detail-line";
      const label = document.createElement("span");
      label.textContent = "Prix au KWh";
      const value = document.createElement("span");
      value.textContent = partner.electricityKwhPrice;
      priceKwh.appendChild(label);
      priceKwh.appendChild(value);
      electricityPriceDetails.appendChild(priceKwh);
    }
    if (partner.electricityKwhPriceHc) {
      const priceKwhHc = document.createElement("div");
      priceKwhHc.className = "detail-line";
      const label = document.createElement("span");
      label.textContent = "Prix au KWh HC";
      const value = document.createElement("span");
      value.textContent = partner.electricityKwhPriceHc;
      priceKwhHc.appendChild(label);
      priceKwhHc.appendChild(value);
      electricityPriceDetails.appendChild(priceKwhHc);
    }
    if (partner.electricityKwhPriceHp) {
      const priceKwhHp = document.createElement("div");
      priceKwhHp.className = "detail-line";
      const label = document.createElement("span");
      label.textContent = "Prix au KWh HP";
      const value = document.createElement("span");
      value.textContent = partner.electricityKwhPriceHp;
      priceKwhHp.appendChild(label);
      priceKwhHp.appendChild(value);
      electricityPriceDetails.appendChild(priceKwhHp);
    }
    energyCard.appendChild(electricityPriceDetails);
  }
  if (partner.gazPrice) {
    const gazPriceDetails = document.createElement("div");
    gazPriceDetails.className = "price-details";
    const headerRow = document.createElement("div");
    headerRow.style.display = "flex";
    headerRow.style.justifyContent = "space-between";
    headerRow.style.alignItems = "center";
    headerRow.style.marginBottom = "15px";
    const title = document.createElement("h3");
    title.className = "price-category";
    title.textContent = "Gaz";
    title.style.margin = "0";
    headerRow.appendChild(title);

    // Add gas percentage difference if available
    if (partner.gazDiffPercentageText) {
      const percentageEconomised = document.createElement("div");
      percentageEconomised.className = "detail-line";
      const percentageEconomisedlabel = document.createElement("span");
      const percentageEconomisedValueDiv = document.createElement("div");
      percentageEconomisedValueDiv.className = "percentage-economised-value-div";
      percentageEconomisedValueDiv.style.backgroundColor = partner.priceColor;
      const percentageEconomisedValue = document.createElement("span");
      percentageEconomisedValue.textContent = partner.gazDiffPercentageText;
      percentageEconomisedValue.style.color = "white";
      percentageEconomised.appendChild(percentageEconomisedlabel);
      percentageEconomisedValueDiv.appendChild(percentageEconomisedValue);
      percentageEconomised.appendChild(percentageEconomisedValueDiv);
      headerRow.appendChild(percentageEconomised);
    }
    gazPriceDetails.appendChild(headerRow);
    const price = document.createElement("div");
    price.className = "detail-line";
    const label = document.createElement("span");
    label.textContent = "Prix de l'abonnement";
    const value = document.createElement("span");
    value.textContent = partner.gazPrice;
    price.appendChild(label);
    price.appendChild(value);
    gazPriceDetails.appendChild(price);
    if (partner.gazKwhPrice) {
      const priceKwh = document.createElement("div");
      priceKwh.className = "detail-line";
      const label = document.createElement("span");
      label.textContent = "Prix au KWh";
      const value = document.createElement("span");
      value.textContent = partner.gazKwhPrice;
      priceKwh.appendChild(label);
      priceKwh.appendChild(value);
      gazPriceDetails.appendChild(priceKwh);
    }
    energyCard.appendChild(gazPriceDetails);
  }
  const features = document.createElement("div");
  features.className = "features";
  const featureCategory = document.createElement("p");
  featureCategory.className = "feature-category";
  featureCategory.textContent = "Les avantages Ideel";
  const featureList = document.createElement("div");
  featureList.className = "feature-list";
  const featuresData = ["20€ de crédits offerts", "Zéro démarche à gérer", "Aucun engagement", "Support Ideel à disposition", "Alerte en cas d'augmentation"];
  featuresData.forEach(featureTitle => {
    const feature = document.createElement("div");
    feature.className = "feature";
    const featureTitleElement = document.createElement("span");
    featureTitleElement.className = "feature-title";
    featureTitleElement.textContent = featureTitle;
    const iconCheck = document.createElement("span");
    iconCheck.className = "icon-check";
    iconCheck.textContent = "✔";
    feature.appendChild(featureTitleElement);
    feature.appendChild(iconCheck);
    featureList.appendChild(feature);
  });
  features.appendChild(featureCategory);
  features.appendChild(featureList);
  energyCard.appendChild(features);
  const selectButton = document.createElement("button");
  selectButton.className = "btn btn-select";
  selectButton.textContent = "Valider la proposition";
  selectButton.addEventListener("click", () => {
    appsmith.triggerEvent("offerChosen", {
      partner: partner.label
    });
  });
  energyCard.appendChild(selectButton);
  const energyOffersContainer = document.querySelector(".energy-offers");
  if (energyOffersContainer) {
    energyOffersContainer.appendChild(energyCard);
  } else {
    console.error('Element with class "energy-offers" not found.');
  }
}

// Au chargement
function renderPage() {
  const partners = appsmith.model.partners;
  // Gestion de la popup d'info
  const overlay = document.querySelector(".info-overlay");
  const infoPopup = overlay.querySelector(".info-popup");
  const closeButton = overlay.querySelector(".close-info");
  const infoText = overlay.querySelector(".info-text");
  closeButton.addEventListener("click", () => {
    overlay.classList.remove("active");
  });
  overlay.addEventListener("click", e => {
    if (e.target === overlay) {
      overlay.classList.remove("active");
    }
  });
  const energyOffersContainer = document.querySelector(".energy-offers");
  energyOffersContainer.innerHTML = "";
  partners.forEach(partner => {
    createCard(partner);
  });
}
appsmith.onReady(() => {
  if (Object.keys(appsmith.model).length > 0) {
    renderPage();
  }
});
appsmith.onModelChange(newModel => {
  if (Object.keys(newModel).length > 0) {
    renderPage();
  }
});

